import{_ as a,o as t,c as b,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"灼热王牌","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/器用类/灼热王牌.md","filePath":"4.资源分区/6.技艺及称号/器用类/灼热王牌.md"}'),s={name:"4.资源分区/6.技艺及称号/器用类/灼热王牌.md"};function o(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"灼热王牌",tabindex:"-1"},[p("灼热王牌 "),r("a",{class:"header-anchor",href:"#灼热王牌","aria-label":'Permalink to "灼热王牌"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),n('<h1 id="灼热王牌-1" tabindex="-1">灼热王牌 <a class="header-anchor" href="#灼热王牌-1" aria-label="Permalink to &quot;灼热王牌&quot;">​</a></h1><p>灼热王牌<br> 好了，你已经握紧了操纵杆！接下来要使出的是冲破黑暗的火箭飞拳，还是抓住胜利的闪光手指？这不重要！<br> 此刻，钢铁的脉搏与你同频，引擎的轰鸣化作心跳——‘钢之魂’正在燃烧！<br> 让敌人见识一下吧，灵魂燃烧的热度方式！<br> 前提：驾驶战斗机器人</p><p>这个距离的话！<br> C+1000<br> 强行近距离战斗的豪迈战术，在抵近距离与对敌人进行一场激烈的射击对决，载具的远程武装不再因为处于对方的触及范围导致高速减半，熟练的技术与勇气让你无惧近距离接触，从而免疫接触攻击。极近距离导致激烈的战斗，这也是你使用这种战术的原因，只要对方在你的触及范围内，你的载具对其进行的任何攻击都获得你驾驶检定主属性附加成功*1的【高速】。</p><p>得手了<br> B+2000<br> 一口气冲到敌人身前，一把将其擒获，随后干脆利落地补上一击。就现在，伸手抓住胜利吧！<br> 攻击技艺，需要至少一个近战武装与一个远程武装，使用整轮动作使用，以移动范围内的一名可以移动到其身边的敌人为目标，立刻冲刺到其身边，再立刻使用一把武器射程基于触及范围的近战载具武装对其进行一次不附带招式的攻击，并且在这次攻击结束后，立刻使用一个远程载具武装对被近战攻击暂时架住的敌人进行一次不附带招式的追加攻击，其中，追加攻击的出目增加一半，表现为第一次攻击限制了敌人的行动，让第二次攻击有充足的时间积蓄力量并攻击对方的要害。</p><p>太乱来了<br> B+2000<br> 迎着对方的攻击冲上去，这太乱来了，但也正因如此，这样大胆的战略才能让对方无法应对。<br> 在自己的回合预留一个标准动作，在任意敌人进行目标包含你的攻击时使用反射动作并支付1意志力使用，使用一个可以攻击到对方的武装进行一次不附带任何招式的打断性攻击，因为在对方攻击时进行反击，所以具有S级先制效果。此外，此次攻击可以选择集中攻击对方发出攻击的肢体，令此次攻击附带对对方进行攻击的肢体的肢体妨碍点数，强韧豁免。</p><p>组合式战术<br> B+2000<br> 这一秒用导弹轰击，下一秒用铁拳挥向对方的面门，各种各样的武器或交错或同时进行袭击，机体搭载的无数武装可不只是好看而已。<br> 复合攻势：现在当你驾驶载具进行攻击时，你可以将至多传奇智力-2或传奇决心-2个其他同样可以攻击到此次攻击的所有目标的其他载具武装加入此次攻击，这意味着这些武装一半的基础属性与全部特性都将加入此次攻击。<br> 迅捷魅影：由于现在你能通过极快的速度来运用载具的武装，这让他人无法确定你使用的武装来进行针对性打击，只要你的载具具有两件及以上的武装，则你的载具具有【免疫击落武器】<br> 特别组合：结合多种攻击能力的战斗产生奇妙的反应，若你在一次载具攻击中参与的武装包括造成物理伤害的武装与造成非物理伤害的武装，则此次攻击获得【法破】。</p><p>全装攻击！<br> 前提：组合式战术<br> A+4000<br> 这就是，我和XX（机体名）的全力<br> 攻击技艺，标准动作支付2意志力释放，使用一件载具武装作为主要载具武装进行一次载具武装攻击，此次攻击必须通过组合式战术的效果导致至少一件近战武装与一件远程武装参与攻击，根据这次攻击的主要武装的类型获得以下两种效果之一。<br> 主要载具武装为近战武装：此次攻击由远程武装削弱对方护甲，再以近战武装将对方撕碎，此次攻击忽略盔甲防御，这是一个A级创伤来源的效果。<br> 主要载具武装为非近战武装：此次攻击由近战武装进行牵制，再以远程武装蓄力释放致命一击，此次攻击忽略闪避防御，这是一个A级变形来源的效果。<br> 致命轰炸，若此次攻击共计有三种及以上的载具武装参与攻击，则强大的威力令此次攻击造成韧性伤害。</p><p>魔神降临<br> A+4000<br> 怎么回事，为什么你们都愣在原地，难道是被那家伙吓到了吗。<br> 使用一个标准动作引发自己与机体的共鸣，让机体感受你的愤怒。在当前场景中，达到高度共鸣的你能够用机体的武装向试图攻击你的人进行报复，面对在你的任一载具武装攻击范围内的敌人所发动的攻击时，你的载具视为具有基于载具护甲值防御类型的，等同于你的决心属性的反伤，伤害类型从可以攻击到该目标的载具武装所能造成的伤害类型中选择。魔神降临期间你获得【威仪】特性，且威仪可以选择你的载具所具有的免疫生效。</p><p>破碎大地<br> A+4000<br> 这是怎样大胆的战术……这是怎样强大的力量……<br> 标准动作支付3意志力使用，使用一件近战载具武装，对大地进行猛击，随后大地开始开裂，这件近战武装常态的攻击范围内的区域，在你的下一轮开始时破碎震颤，地形发生翻天覆地的变化，范围内的地面陷落至多300M，原本的环境效果如同被S级异空间覆盖一般失效（这个异空间效果不会影响任何人的进出异空间范围，但需要有办法越过300M高的悬崖），范围内区域进入A级环境来源的地震状态，区域边缘则因为相对于陷落的区域视为悬崖地形。生效期间无法再次使用这个能力，在生效时间结束后大地逐渐抬升恢复，大概是超级系动漫的奇怪定律导致的，但期间因为地震损坏的建筑等不会恢复。</p><p>魂之一击<br> A+5000<br> 强烈地牵绊下，为了什么让灵魂熊熊燃烧。这一刻，这一秒，不去为了什么全力以赴，就算不上男子汉了。不用管什么道理，这一刻，就是能做到。<br> 一影片一次，在满足以下条件之一时才能使用：<br> 1&gt;爱，当前场景存在你所爱的，且自身同样爱着你的，可以称为是你的恋人的，且不是你的随从或其他同PL操作的单位。石破LOVE LOVE天惊<br> 2&gt;希望，当前场景中至少一半的友方角色结构值低于一半或失去完好<br> 3&gt;决意，你剩余的韧性值或结构值不高于你的耐力属性<br> 4&gt;责任，这场战斗关乎世界的存亡，且至少有一个城市的平民在期望你们获得胜利<br> 使用标准动作，支付4点意志力才能使用，进行一次载具武装攻击，此次攻击具有【传奇】特性，且附带A级命运来源的SSS级即死效果，意志豁免。</p><p>专长：<br> 热忱王牌（3）<br> 前提：组合式战术<br> 激发心中的热忱，在激战中激发自己的操作潜力。<br> 你可以以自由动作并支付1意志激发自身潜力，在当前场景中组合式战术所允许加入攻击的武器数量再+2，并适用组合式战术的限制（同样可以攻击到此次攻击的所有目标的其他载具武装）与效果（这些武装一半的基础属性与全部特性都将加入此次攻击）。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const A=a(s,[["render",o]]);export{f as __pageData,A as default};
